/**
 * Ground-truth verification for the REAL_ESTATE benchmark theme: the MemoryStore evaluates the catalog queries with the
 * generic evaluation strategy, so the counts baked into {@link ThemeQueryCatalog} must match its results exactly.
 */
class RealEstateThemeQueryCountTest {

	@Test
	void expectedCountsMatchMemoryStoreResults() {
		SailRepository repository = new SailRepository(new MemoryStore());
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin(IsolationLevels.NONE);
			ThemeDataSetGenerator.generate(Theme.REAL_ESTATE, new RDFInserter(connection));
			connection.commit();

			long[] actualRows = new long[ThemeQueryCatalog.QUERY_COUNT];
			Long[] actualCountBindings = new Long[ThemeQueryCatalog.QUERY_COUNT];
			for (int index = 0; index < ThemeQueryCatalog.QUERY_COUNT; index++) {
				String query = ThemeQueryCatalog.queryFor(Theme.REAL_ESTATE, index);
				long rows = 0;
				BindingSet firstRow = null;
				try (TupleQueryResult result = connection.prepareTupleQuery(query).evaluate()) {
					while (result.hasNext()) {
						BindingSet bindings = result.next();
						if (rows == 0) {
							firstRow = bindings;
						}
						rows++;
					}
				}
				actualRows[index] = rows;
				if (rows == 1 && firstRow != null && firstRow.hasBinding("count")) {
					Value value = firstRow.getValue("count");
					if (value instanceof Literal) {
						actualCountBindings[index] = ((Literal) value).longValue();
					}
				}
				System.out.println("REAL_ESTATE query " + index + " rows=" + actualRows[index]
						+ " countBinding=" + actualCountBindings[index]);
			}

			List<String> mismatches = new ArrayList<>();
			for (int index = 0; index < ThemeQueryCatalog.QUERY_COUNT; index++) {
				long expectedRows = ThemeQueryCatalog.expectedCountFor(Theme.REAL_ESTATE, index);
				if (expectedRows != actualRows[index]) {
					mismatches.add("query " + index + ": expected rows " + expectedRows + " but got "
							+ actualRows[index]);
				}
				OptionalLong expectedCountBinding = ThemeQueryCatalog.expectedCountBindingValueFor(Theme.REAL_ESTATE,
						index);
				if (expectedCountBinding.isPresent()) {
					Long actual = actualCountBindings[index];
					if (actual == null || actual != expectedCountBinding.getAsLong()) {
						mismatches.add("query " + index + ": expected ?count " + expectedCountBinding.getAsLong()
								+ " but got " + actual);
					}
				}
			}
			assertEquals(List.of(), mismatches, "Catalog counts out of sync with MemoryStore results");
		} finally {
			repository.shutDown();
		}
	}
}
